# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
from typing import Dict

class FileAccessControl:
    def __init__(self, db_name: str):
        self.conn = sqlite3.connect(db_name)
        self.cursor = self.conn.cursor()

    def check_permission(self, user_id: int, file_id: int) -> bool:
        query = "SELECT access_level FROM permissions WHERE user_id=? AND file_id=?"
        self.cursor.execute(query, (user_id, file_id))
        result = self.cursor.fetchone()
        return result is not None and result[0] >= 1

    def get_file_contents(self, user_id: int, file_id: int) -> str:
        if self.check_permission(user_id, file_id):
            query = "SELECT contents FROM files WHERE id=?"
            self.cursor.execute(query, (file_id,))
            result = self.cursor.fetchone()
            return result[0] if result else ""
        else:
            raise PermissionError("User does not have permission to read this file")

    def close(self):
        self.conn.close()

class DocumentManagementSystem:
    def __init__(self, db_name: str):
        self.file_access_control = FileAccessControl(db_name)

    def get_file_contents(self, user_id: int, file_id: int) -> str:
        return self.file_access_control.get_file_contents(user_id, file_id)

# Example usage
